=📚 <b>Deep Research Tool</b>

📌 <b>Topic:</b> {{ $json.topic }}
🎥 <b>Type:</b> {{ $json.videoType === 'short' ? '⚡ Quick Research' : '📽 Deep Research' }}

🔍 Analyzing sources from web, YouTube, articles &amp; blogs...
⏳ Give me 2 minutes!

parameters.jsCode:
const allData = $input.all();
const topic = $('Parse Input').item.json.topic;
const chatId = $('Parse Input').item.json.chatId;

let webSources = []; let youtubeSources = []; let hnSources = []; let blogSources = [];
let tavilyAnswer = '';

for (const item of allData) {
  const d = item.json;
  if (d.answer && d.answer.length > 10) tavilyAnswer = d.answer;

  // Tavily web
  if (d.results && Array.isArray(d.results)) {
    for (const r of d.results) {
      webSources.push({
        type: 'WEB',
        title: (r.title||'').substring(0,100),
        url: r.url||'',
        content: (r.content||r.snippet||'').substring(0,500),
        score: r.score||0
      });
    }
  }

  // YouTube
  if (d.items && Array.isArray(d.items)) {
    for (const v of d.items) {
      youtubeSources.push({
        title: (v.snippet?.title||'').substring(0,100),
        channel: v.snippet?.channelTitle||'Unknown',
        description: (v.snippet?.description||'').substring(0,400),
        videoId: v.id?.videoId||'',
        publishedAt: (v.snippet?.publishedAt||'').substring(0,10)
      });
    }
  }

  // HackerNews
  if (d.hits && Array.isArray(d.hits)) {
    for (const h of d.hits) {
      if (h.url) hnSources.push({
        type: 'ARTICLE',
        title: (h.title||'').substring(0,100),
        url: h.url,
        content: (h.story_text||h._highlightResult?.title?.value||'Community discussion thread').substring(0,300),
        points: h.points||0
      });
    }
  }

  // Dev.to
  if (Array.isArray(d)) {
    for (const a of d) {
      blogSources.push({
        type: 'BLOG',
        title: (a.title||'').substring(0,100),
        url: a.url||'',
        content: (a.description||a.body_markdown||'').substring(0,400),
        reactions: a.public_reactions_count||0
      });
    }
  }
}

// Deduplicate web
const seenUrls = new Set();
webSources = webSources.filter(s => { if (!s.url||seenUrls.has(s.url)) return false; seenUrls.add(s.url); return true; });

// Sort by score
webSources.sort((a,b) => (b.score||0)-(a.score||0));
hnSources.sort((a,b) => (b.points||0)-(a.points||0));
blogSources.sort((a,b) => (b.reactions||0)-(a.reactions||0));

// Best source = highest scored web result
const bestSource = webSources[0] || null;

// Build compact AI context (tokens limited)
const aiContext = [
  tavilyAnswer ? 'RESEARCH SUMMARY: ' + tavilyAnswer : '',
  webSources.slice(0,5).map(s=>`[WEB] ${s.title}\nURL: ${s.url}\n${s.content.substring(0,200)}`).join('\n'),
  hnSources.slice(0,3).map(s=>`[ARTICLE] ${s.title}\nURL: ${s.url}\n${s.content.substring(0,150)}`).join('\n'),
  blogSources.slice(0,3).map(s=>`[BLOG] ${s.title}\nURL: ${s.url}\n${s.content.substring(0,150)}`).join('\n')
].filter(Boolean).join('\n\n');

const ytContext = youtubeSources.slice(0,5).map(v=>`TITLE: ${v.title}\nCHANNEL: ${v.channel}\nDESCRIPTION: ${v.description}\nLINK: https://youtube.com/watch?v=${v.videoId}`).join('\n---\n');

return [{ json: { topic, chatId, tavilyAnswer, bestSource, webSources: webSources.slice(0,8), youtubeSources: youtubeSources.slice(0,6), hnSources: hnSources.slice(0,5), blogSources: blogSources.slice(0,5), aiContext, ytContext } }];

const topic = $('Parse Input').item.json.topic;
const researchAnalysis = $('Deep Research Analysis').item.json.text || '';
const sourceAnalysis = $('Source Deep Analysis').item.json.text || '';
const webSources = $('Compress Long Research').item.json.webSources || [];
const youtubeSources = $('Compress Long Research').item.json.youtubeSources || [];
const hnSources = $('Compress Long Research').item.json.hnSources || [];
const blogSources = $('Compress Long Research').item.json.blogSources || [];
const date = new Date().toISOString().split('T')[0];

const parseSection = (text, label) => {
  const regex = new RegExp(label + '[:\\s]*([\\s\\S]*?)(?=\\n[A-Z][A-Z &]+:|$)', 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : 'Not available.';
};

const quickSummary   = parseSection(researchAnalysis, 'QUICK SUMMARY');
const keyFacts       = parseSection(researchAnalysis, 'KEY FACTS & DATA');
const keyInsights    = parseSection(researchAnalysis, 'KEY INSIGHTS FROM SOURCES');
const controversies  = parseSection(researchAnalysis, 'CONTROVERSIES OR CRITICISM');
const trends         = parseSection(researchAnalysis, 'IMPORTANT TRENDS');
const videoAngles    = parseSection(researchAnalysis, 'VIDEO CONTENT ANGLES');
const totalSources   = webSources.length + youtubeSources.length + hnSources.length + blogSources.length;

// ── Google Docs batchUpdate request builder ──────────────────────────────────
const requests = [];
let curIdx = 1;

function addText(text) {
  if (!text) return;
  requests.push({ insertText: { location: { index: curIdx }, text } });
  curIdx += text.length;
}

function addLink(url, displayText) {
  if (!url) return;
  const linkText = displayText || url;
  const startIdx = curIdx;
  requests.push({ insertText: { location: { index: curIdx }, text: linkText + '\n' } });
  const endIdx = curIdx + linkText.length; // exclusive end (excludes \n)
  curIdx += linkText.length + 1;
  requests.push({
    updateTextStyle: {
      range: { startIndex: startIdx, endIndex: endIdx },
      textStyle: {
        link: { url },
        foregroundColor: { color: { rgbColor: { red: 0.0627, green: 0.4627, blue: 0.9255 } } },
        underline: true
      },
      fields: 'link,foregroundColor,underline'
    }
  });
}

function addH1(text) {
  const startIdx = curIdx;
  requests.push({ insertText: { location: { index: curIdx }, text: text + '\n' } });
  const endIdx = curIdx + text.length + 1;
  curIdx += text.length + 1;
  requests.push({
    updateParagraphStyle: {
      range: { startIndex: startIdx, endIndex: endIdx },
      paragraphStyle: { namedStyleType: 'HEADING_1' },
      fields: 'namedStyleType'
    }
  });
}

function addH2(text) {
  const startIdx = curIdx;
  requests.push({ insertText: { location: { index: curIdx }, text: text + '\n' } });
  const endIdx = curIdx + text.length + 1;
  curIdx += text.length + 1;
  requests.push({
    updateParagraphStyle: {
      range: { startIndex: startIdx, endIndex: endIdx },
      paragraphStyle: { namedStyleType: 'HEADING_2' },
      fields: 'namedStyleType'
    }
  });
}

// ── Build document ────────────────────────────────────────────────────────────
addH1('DEEP RESEARCH DOCUMENT');
addText('Topic: ' + topic + '\n');
addText('Generated: ' + date + '\n');
addText('Total Sources Analyzed: ' + totalSources + '\n\n');

addH1('QUICK SUMMARY');
addText(quickSummary + '\n\n');

addH1('KEY FACTS & DATA');
addText(keyFacts + '\n\n');

addH1('KEY INSIGHTS FROM SOURCES');
addText(keyInsights + '\n\n');

addH1('CONTROVERSIES OR CRITICISM');
addText(controversies + '\n\n');

addH1('IMPORTANT TRENDS');
addText(trends + '\n\n');

addH1('VIDEO CONTENT ANGLES');
addText(videoAngles + '\n\n');

addH1('DETAILED SOURCE ANALYSIS');
addText(sourceAnalysis + '\n\n');

addH1('BEST SOURCES FOR DEEPER EXPLORATION');
webSources.slice(0, 3).forEach((s, i) => {
  addText('\n' + (i + 1) + '. ' + s.title + '\n');
  addLink(s.url);
  addText('Date: ' + (s.publishedAt || 'Not available') + '\n');
  addText('Key Insights:\n' + s.content.substring(0, 300) + '...\n\n');
});
youtubeSources.slice(0, 2).forEach((s, i) => {
  const ytUrl = 'https://youtube.com/watch?v=' + s.videoId;
  addText('\n' + (Math.min(webSources.length, 3) + i + 1) + '. ' + s.title + '\n');
  addLink(ytUrl);
  addText('Channel: ' + s.channel + ' | Date: ' + (s.publishedAt || 'Unknown') + '\n');
  addText('Description:\n' + s.description.substring(0, 250) + '...\n\n');
});

addH1('ALL REFERENCES');

if (webSources.length > 0) {
  addH2('WEB ARTICLES');
  webSources.forEach((s, i) => {
    addText((i + 1) + '. ' + s.title + '\n');
    addLink(s.url);
  });
  addText('\n');
}

if (youtubeSources.length > 0) {
  addH2('YOUTUBE VIDEOS');
  youtubeSources.forEach((s, i) => {
    const ytUrl = 'https://youtube.com/watch?v=' + s.videoId;
    addText((i + 1) + '. ' + s.title + ' (' + s.channel + ')\n');
    addLink(ytUrl);
  });
  addText('\n');
}

if (hnSources.length > 0) {
  addH2('COMMUNITY ARTICLES');
  hnSources.forEach((s, i) => {
    addText((i + 1) + '. ' + s.title + '\n');
    addLink(s.url);
  });
  addText('\n');
}

if (blogSources.length > 0) {
  addH2('BLOG POSTS');
  blogSources.forEach((s, i) => {
    addText((i + 1) + '. ' + s.title + '\n');
    addLink(s.url);
  });
}

addText('\n\n─── END OF RESEARCH DOCUMENT ───\n');

return [{ json: {
  topic,
  batchRequests: requests,
  chatId: $('Parse Input').item.json.chatId,
  totalSources
} }];
